var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"무, 무슨 거래인데?","JPN":"ど、どういう取引なんだ？","ENG":"W-what kind of deal is it?","TWN":"那、那是什麼交易？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"서, 설마 이 구속구를 채운 것도 그런 이유였나?","JPN":"ま、まさかこの拘束具をつけたのもそういう理由だったとか？","ENG":"D-don't tell me that's why you put these restraints on me?","TWN":"難、難道這個束具也是為了這個理由？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"미안하지만, 난 누구처럼 웃통 깐 근육 아저씨 수발 들 생각은 추호도 없거든?","JPN":"悪いけど、あたしは誰かさんみたいに上半身丸出しのマッチョなおっさんの世話をするつもりはこれっぽちもないから。","ENG":"Sorry, but I'm not about to wait hand and foot on some shirtless muscle-head like you-know-who.","TWN":"抱歉，我可沒像某人有伺候裸上身肌肉大叔的想法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"왜 저를 바라보시는 거죠?","JPN":"どうして私を見るのですか？","ENG":"Why are you looking at me?","TWN":"妳為什麼那樣看我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그리고, 그런 이유 아니거든요?!","JPN":"それに、そんな理由ではありません！","ENG":"And that is absolutely not the reason!","TWN":"而且也不是那種理由吧？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 그런 거래였으면 말을 꺼내지도 않았을 거야.","JPN":"ハハハ！　そんな取引だったら、最初から口にするほどのものでもないさ。","ENG":"Gah hah hah! If that were the deal, I wouldn't have brought it up.","TWN":"哈哈哈！如果是那種理由，我根本不會開口。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 아가씨라면 분명… 충분히 응할 수 있는 조건이라고 생각하거든.","JPN":"だがお嬢さんならきっと……十分に応えられる条件だと思う。","ENG":"But I think... you'll find the conditions perfectly acceptable.","TWN":"但如果是小姐，我相信……妳完全可以接受這條件。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트 베이는 현재 예상치 못한 검은 범람으로 위기 상황이야.","JPN":"フロントベイは今、想定外の黒い氾濫という危機的状況に直面している。","ENG":"Front Bay is in crisis from an unexpected Black Flood.","TWN":"前灣目前因為意想不到的黑色洪災陷入危機。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"격벽엔 수많은 침식체가 몰려들어 틈을 파고들고 있고, 이를 막을 병사는 턱없이 부족하지.","JPN":"隔壁には数多くの侵食体が押し寄せて隙間から入り込もうとしているが、それを食い止めるための兵士がとにかく足りない。","ENG":"Countless C.O.s are swarming the bulwark and breaking through, and we're severely short on soldiers to hold them off.","TWN":"隔離牆聚集了無數侵蝕體試圖突破，但阻止它們的兵力嚴重不足。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"도시는 중앙의 관리국 본부를 기준으로 여러 섹터로 나뉘어져 있어.","JPN":"都市は中央の管理局本部を基準として、いくつかのセクターに分けられている。","ENG":"The city is divided into multiple sectors, with the Administration HQ at the center.","TWN":"城市以中央的管理局本部為中心，向外劃分多個區域。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 그렇게 나뉜 섹터를 기준으로 격벽을 구분하지.","JPN":"そして、そうやって分けられたセクターごとに隔壁を区別している。","ENG":"And those sectors define the bulwark divisions.","TWN":"隔離牆也是依照各區域設置。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨가 할 일은 간단해.","JPN":"お嬢さんにやってもらいたいことは、いたって簡単さ。","ENG":"Your job is simple.","TWN":"小姐要做的事很簡單。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"각 섹터에서 들어오는 지원 요청을 받아 그쪽의 일을 해결하는 거지.","JPN":"各セクターから入ってくる支援要請を受け、それを解決するんだ。","ENG":"You'll take on the support requests coming from each sector and resolve the problems there.","TWN":"接收各區域的支援請求，解決那裡的問題。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 도시의 지원 요청을 모두 해결한다면…….","JPN":"都市の支援要請をすべて解決できれば……","ENG":"And if you manage to complete all the city's requests...","TWN":"當解決所有城市的支援請求後……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨는 자유의 몸을 되찾고, 프론트 베이도 사람들에게 돌려줄 수 있지.","JPN":"お嬢さんは晴れて自由の身となり、フロントベイも取り戻せる。","ENG":"You'll gain your freedom, and Front Bay can be returned to its people.","TWN":"小姐就能恢復自由，也能將前灣還給人民。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"만약 실패한다면……?","JPN":"もし失敗したら……？","ENG":"And if I fail...?","TWN":"如果失敗呢……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫, 뭘 당연한 소리를 하고 그러나?","JPN":"ハハッ、何を分かりきったことを。","ENG":"Haha, isn't it obvious?","TWN":"哈哈，妳說什麼廢話呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리 다 함께 손잡고 죽는 거지.","JPN":"みんな仲良く死ぬだけだ。","ENG":"We all join hands and die together.","TWN":"我們大家一起手牽手死掉啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 그건 거래가 아니라 협박이잖아.","JPN":"くそ、もはや取引どころか、だだの脅迫じゃねぇか。","ENG":"Damn it, that's not a deal. That's a threat.","TWN":"可惡。這不是交易，而是威脅。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님이 그 정도로 배려해 주신 것도 고맙게 생각하세요.","JPN":"シニア様がここまで配慮してくださったことに感謝すべきです。","ENG":"You should be grateful the Senior offered even that level of mercy.","TWN":"Senior應該要感謝他這麼體貼。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"원래라면 아케론에서 평생을 썩었야 했던 거, 아시죠?","JPN":"本来ならアケロンで一生を終えるはずだったのはご存じですよね？","ENG":"You know you would be rotting in Acheron for life under normal circumstances.","TWN":"妳原本應該在黃泉度過一生，不是嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"흥, 지들이 멋대로 결정해 놓고는.","JPN":"ふん、自分たちで勝手に決めたくせに。","ENG":"Hmph, deciding everything on their own and acting like they're doing me a favor.","TWN":"哼，還不是你們擅自作主。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그건 그렇고, 너는 왜 내 옆에서 쫑알거리는 거야?","JPN":"それはそうとして、お前なんであたしの横でぶつぶつ言ってるわけ？","ENG":"Anyway, why are you yapping next to me?","TWN":"對了，你為什麼在我身邊嘰嘰喳喳？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"시니어 옆에서 시끄럽게 잔소리나 하러 가라고.","JPN":"がみがみ小言言うのは、シニアの隣に行ってやれよ。","ENG":"Go nag next to the Senior or something.","TWN":"去Senior旁邊鬧吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저는 당신의 출력을 통제할 의무가 있어요.","JPN":"私にはあなたの出力を統制する義務があります。","ENG":"I'm responsible for controlling your output.","TWN":"我有義務控制妳的輸出。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님도 허락한 사안이니까, 도망칠 생각은 안 하시는 게 좋을걸요?","JPN":"シニア様もお許しになった件ですので、逃げるなんて夢にも思わないことです。","ENG":"And since the Senior approved it, you'd better not think about running.","TWN":"Senior也允許了，所以最好別想逃跑"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장… 이렇게 답답한 상황은 딱 질색인데.","JPN":"くそ……こういう窮屈な状況って苦手なんだけどな。","ENG":"Damn it... I hate being boxed in like this.","TWN":"可惡……這種讓人窒息的情況真討厭。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그래서 우리는 어디로 가면 돼?","JPN":"で、どこに行けばいいんだ？","ENG":"So where are we supposed to go first?","TWN":"那我們該去哪裡？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저희가 먼저 향할 곳은 5 섹터예요.","JPN":"私たちが最初に向かう場所はセクター5です。","ENG":"We'll be heading to Sector 5.","TWN":"我們首先要去的是第5區。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"음? 거기는…….","JPN":"うん？　そこって……","ENG":"Hmm? That's...","TWN":"嗯？那裡是……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네, 맞아요.","JPN":"はい、そうです。","ENG":"Yes, that's right.","TWN":"對，沒錯。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"당신이 5년 전에 선상 반란으로 큰 피해를 본 곳 중 하나죠.","JPN":"5年前、あなたが起こした船上反乱のせいで、大きな被害を受けた場所の1つです。","ENG":"It's one of the places heavily damaged by your rebellion five years ago.","TWN":"是5年前因船上叛亂而遭受重大損失的地方之一。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 4시간 경과","JPN":"黒い氾濫の発生から4時間経過","ENG":"4 hours since the Black Flood onset","TWN":"黑色洪災發生4小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>프론트 베이</color> 5 섹터","JPN":"管理局直轄都市<color=#ffd34c>フロントベイ</color>、セクター5","ENG":"Administration Direct Control City, <color=#ffd34c>Front Bay</color>, Sector 5","TWN":"管理局直轄城市<color=#ffd34c>前灣</color>第5區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"관리국은 지난 검은 범람 때 사냥꾼들의 활약을 눈여겨 보고 있었습니다.","JPN":"管理局は前の黒い氾濫の時、海賊とハンターの活躍に注目していました。","ENG":"During the last Black Flood, the Administration saw how well the pirates and hunters worked together.","TWN":"管理局在上次黑色洪災時，注意到獵人們的活躍表現。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"이에 따라 정책을 변경, 저희는 격벽을 폐쇄하지 않습니다!","JPN":"これにより政策を変更、我々は隔壁を閉鎖しません！","ENG":"Accordingly, we've changed our policy, so we won't close the bulwark!","TWN":"因此調整政策，不再封閉隔離牆！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"대신 헌터와 해적, 사냥꾼분들에게 의뢰를 할당하기로 했습니다!","JPN":"その代わり、海賊とハンターの皆さんに仕事を依頼することに決めました！","ENG":"Instead, we're assigning requests to the hunters and pirates!","TWN":"取而代之的是委派獵人、海盜和獵手們處理任務！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"여러분이 해야 할 일은 간단합니다!","JPN":"皆さんのお仕事はシンプルです！","ENG":"Your task is simple!","TWN":"你們要做的事很簡單！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"격벽 밖으로 나가 침식체들을 쓸어버리는 거죠!","JPN":"隔壁の外に出て侵食体を始末すること！","ENG":"Go beyond the bulwark and sweep away the C.O.s!","TWN":"走出隔離牆，清除侵蝕體！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"침식체를 많이 잡을수록 관리국에서 주는 포상금도 늘어나니 힘내주시기 바랍니다!","JPN":"倒した侵食体の数が多いほど、管理局からの褒賞金も増えますので頑張ってください！","ENG":"The more C.O.s you defeat, the greater the rewards from the Administration, so do your best!","TWN":"捕獲的侵蝕體越多，管理局給的獎勵金也越多，加油吧！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"젠장, 관리국 자식들 입만 살아서는 나불거린단 말이지.","JPN":"くそ、管理局のやつら調子のいいこと言いやがって。","ENG":"Damn it, those Administration bastards sure love to flap their mouths.","TWN":"可惡，管理局那些傢伙只會出一張嘴。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"결국 바다로 나와서 싸우는 건 우리 해적들이잖아.","JPN":"結局海に出て戦うのは俺たち海賊じゃねえか。","ENG":"In the end, we're the ones who have to head out to sea and fight.","TWN":"最後真正出海戰鬥的還是我們海盜。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"허, 마치 너희 해적들이 바다 위에선 무적인 것처럼 말하는군.","JPN":"はっ、海賊が海の上では無敵だとでもいうような口ぶりだな。","ENG":"Hah, you talk like pirates are invincible on the ocean.","TWN":"哈，講得好像你們海盜在海上無敵似的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"우리가 없었다면, 너희 해적들은 그저 크라켄의 한 끼 식사가 될 뻔한 거 아니었나?","JPN":"俺たちがいなかったら、お前ら海賊はクラーケンのエサになるところだったのにな？","ENG":"If not for us hunters, you'd have been Kraken chow last time.","TWN":"如果不是我們，你們海盜不就成了克拉肯的一頓大餐嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"아앙? 너 말 다했냐?","JPN":"ああーん？　テメエ、なんつった？","ENG":"Huh? You done talkin'?","TWN":"啊？你說完了嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"너희야말로 그때, 아기처럼 울면서 건져 올려달라고 하지 않았어?","JPN":"お前らこそあの時、赤ちゃんみたいに、引き上げてくれ～って泣いてたよなあ？","ENG":"Weren't you the ones crying like babies for us to haul you up back then?","TWN":"你們那時候才像個孩子哭著求我們救你們上來吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"흥, 여전히 짜증 나는 녀석들이군.","JPN":"ふん、相変わらずむかつくやつらだ。","ENG":"Hmph, still as irritating as ever.","TWN":"哼，還真是煩人的傢伙。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"너희도 마찬가지다. 헌터.","JPN":"お前らもな、ハンター。","ENG":"Same goes for you, hunter.","TWN":"你們也一樣，獵人。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PIRATE_HUNTERS_NPC_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PIRATE_HUNTERS_NPC_NULL","text":{"KOREA":"일단은 검은 범람을 잠재우는 게 우선이겠지.","JPN":"まずは黒い氾濫を抑えるのが先だな。","ENG":"For now, stopping the Black Flood comes first.","TWN":"我們得先抑制黑色洪災吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L46_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"방식은 저번과 같다.","JPN":"やり方はこの前と同じだ。","ENG":"Same strategy as last time.","TWN":"方法和上次一樣。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"케헤헤, 누가 더 많이 잡는지 토큰을 걸고 내기하자는 거지?","JPN":"クヘヘ、誰が多く倒せるか、トークンかけて勝負ってことだな？","ENG":"Kehehe, so we're betting tokens on who kills more, right?","TWN":"呵呵呵，要不要賭上代幣看誰抓得多？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"괜히 꼴사납게 뒈지지 말라고?","JPN":"みっともなくくたばるなよ？","ENG":"Just don't die like an idiot, okay?","TWN":"不要白白輸掉比賽？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIRATE_NPC_NULL_FAST","text":{"KOREA":"이런 간단한 내기에서 죽어버리는 것만큼 꼴사나운 짓도 없으니까.","JPN":"こんな簡単な賭けで死んじまったりでもしてみろ、カッコ悪いにもほどがある。","ENG":"Dying in an easy wager like this would be the most pathetic thing ever.","TWN":"在這種簡單賭局中死掉的話最難看了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_NULL_FAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"너희도 마찬가지다.","JPN":"その言葉そっくり返すぜ。","ENG":"Same goes for you.","TWN":"你們也一樣。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_NULL","text":{"KOREA":"괜히 방심했다가 죽어서 김새는 짓은 하지 말도록.","JPN":"油断して死んで、がっかりさせるなよ。","ENG":"Don't ruin the mood by dying from carelessness.","TWN":"別因為輕敵死掉壞了好事。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_VETERAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_QM","text":{"KOREA":"뭘 그렇게 신기하게 보고 있어?","JPN":"何をそんなに不思議そうに見てるんだ？","ENG":"What's so fascinating?","TWN":"幹嘛用這麼新奇的眼神看我們？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"해적과 외지인이… 서로 협력한다고?","JPN":"海賊とよそ者が……協力し合っている？","ENG":"Pirates and outsiders... actually cooperating?","TWN":"海盜和外地人……竟然合作？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"분명 서로 으르렁거리던 사이 아니었어?","JPN":"いつもいがみ合ってたのに？","ENG":"Weren't they snarling at each other before?","TWN":"你們明明剛剛還在互相咆哮啊？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아, 별거 아냐. 신경 쓰지 마.","JPN":"ああ、大したことじゃない。気にするな。","ENG":"Ah, don't mind that. It's nothing.","TWN":"啊，沒什麼，別在意。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"어차피 저러다가 또 자기들끼리 쏠 거거든.","JPN":"どうせそのうちまた撃ち合いを始めるんじゃないの？","ENG":"Give it a bit and they'll be shooting each other again.","TWN":"反正他們很快就會再吵起來。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"너 이 자식! 방금 그건 우리 해적단의 작살이 박힌 놈이었다고!","JPN":"テメエ！　今のその獲物、俺たち海賊団の銛が刺さってたやつだったろ！","ENG":"You bastard! That one had our harpoon in it!","TWN":"你這傢伙！你剛才才被我們海盜團的魚叉打中欸！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"작살? 이 줄이 끊어진 채 우리 쪽으로 넘어온 고철을 말하는 거냐?","JPN":"銛だぁ？　さっき俺たちの方に流れてきた、この綱の切れた鉄くずのことか？","ENG":"Your harpoon? You mean that scrap that drifted to our side with the line snapped?","TWN":"魚叉？是那個斷裂掉到我們這邊的廢鐵嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"더 이상 못 참아! 얘들아, 쏴라!","JPN":"もう我慢できねえ！　野郎ども、撃て！","ENG":"I've had enough! Fire!","TWN":"我再也忍不了了！大家開火！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"봤지?","JPN":"ほら。","ENG":"See?","TWN":"妳看吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_QM","text":{"KOREA":"캬하핫, 겨우 저런 게 신기했던 거야? 조금 허접 같고 귀엽잖아?","JPN":"キャハハッ、あんなのが不思議だったのか？　ヘタクソなところがちょっと可愛いじゃねぇか。","ENG":"Kyahaha! That's what amazed you? Kinda lame, but cute.","TWN":"哈哈哈，就這樣妳就覺得新奇？有點簡陋又可愛吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"샤크스의 배에 오른 걸 환영한다.","JPN":"シャークスの船にようこそ。","ENG":"Welcome aboard the Sharks' ship.","TWN":"歡迎登上大白鯊的船。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네 이름은 익히 들어 알고 있어.","JPN":"お前の名前はよく耳に入ってくるから知ってるよ。","ENG":"I've heard plenty about you.","TWN":"久仰大名。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"프론트 베이 최악의 범죄자, 키이라. 맞지?","JPN":"フロントベイ最悪の犯罪者、キーラ。だろ？","ENG":"Front Bay's worst criminal. Kiera, right?","TWN":"前灣最惡名昭彰的罪犯，琪伊拉。對吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"잠깐만… 여기 좀 봐줄래?","JPN":"ちょっとだけ……こっち見てくれないか？","ENG":"Hold on... Look here for a sec.","TWN":"等等……妳能看一下這邊嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 윙스타에 난리가 나겠구만.","JPN":"キャハハッ！　ウィングスターが大騒ぎになるぞ。","ENG":"Kyahaha! Wing-stagram is gonna explode over this.","TWN":"哈哈哈！社群平台要瘋了吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L47_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>안녕, 허접 자식들? 난 프론트 베이 선상 반란의 주동자랑 함께 있어.</color>","JPN":"<color=#ffd34c>やあ、ヘタクソども。あたしさ、今フロントベイ船上反乱の首謀者と一緒にいるけどよ。</color>","ENG":"<color=#ffd34c>Hey there scurvy dogs. I'm here with the ringleader of Front Bay's rebellion.</color>","TWN":"<color=#ffd34c>你好，廢物們？我和前灣船上叛亂的主謀在一起。</color>"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>지금 검은 범람으로 난리니까, 한탕 해 먹고 싶은 놈들은 바다로 나오도록. 이상.</color>","JPN":"<color=#ffd34c>ちょうど黒い氾濫が起きて大騒ぎしてるから、儲けたいやつは海に出るように。以上。</color>","ENG":"<color=#ffd34c>The Black Flood's a mess right now, so if you want a big score, get out on the water. That's all.</color>","TWN":"<color=#ffd34c>現在因為黑色洪災亂成一團，想撈一筆的就出海吧，以上。</color>"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통.","JPN":"おい、ポンコツ。","ENG":"Hey, tin can.","TWN":"喂，鐵桶。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"얘네 배에 타는 게 맞아?","JPN":"こいつらの船に乗っていいのか？","ENG":"Are we really supposed to be on their ship?","TWN":"登上他們的船合適嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"죄다 나사가 하나씩 빠져 있는 것 같은데.","JPN":"全員頭がイカれてるっぽいけど。","ENG":"Feels like everyone here is missing a screw.","TWN":"感覺好像每個人都少了一顆螺絲。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"샤크스 해적단은 나름 라이선스도 있는 태스크포스에요.","JPN":"シャークス海賊団は、こう見えてもライセンス持ちのタスクフォースです。","ENG":"Sharks Pirates are a licensed TASKFORCE, actually.","TWN":"大白鯊海盜團其實是有執照的特遣勢力。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"우리 거래, 잊지 않으셨죠?","JPN":"取引のこと、忘れていませんよね？","ENG":"You haven't forgotten our deal, right?","TWN":"我們的交易，你還記得吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……쳇, 이놈이나 저놈이나 마음에 안 들어.","JPN":"……チッ、どいつもこいつも気に入らねえな。","ENG":"...Tch. I don't like any of this.","TWN":"……哼，不管哪一邊我都不喜歡。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국에게 스스로 목줄을 맡긴 셈이라니.","JPN":"自分から管理局に手綱を預けるなんて。","ENG":"You're letting the Administration put a leash on your neck.","TWN":"這無疑是把自己的項圈交給管理局。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흐음? 관리국에 목줄을 맡겨?","JPN":"ふーん？　管理局に手綱を預ける？","ENG":"Hmm? Let the Administration leash us?","TWN":"嗯？把項圈交給管理局？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 어떤 멍청이가 그런 짓을 해?","JPN":"キャハハッ！　どこのバカがそんなマネするかよ。","ENG":"Kyahaha! What kind of idiot would let that happen?","TWN":"哈哈哈！哪個傻瓜會幹這種事？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼, 지금 이 행동들이 관리국에 끌려다니는 모양새가 아니라는 거야?","JPN":"じゃあ、今のこれは管理局に言われるがまま、振り回されているってわけじゃないとでも？","ENG":"So you're saying you're not being dragged around by the Administration right now?","TWN":"那麼你是說現在這些行動不受管理局牽制？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"당연하지. 해적들은 애초에 누구 말을 듣는 사람들이 아니걸랑.","JPN":"当たり前だろ。大体海賊ってものはよ、他人の言葉になんか従わないのさ。","ENG":"Of course not. Pirates don't take orders from anyone.","TWN":"當然不是。海盜從來不會聽別人的話。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};